sp_rectangle_menu_item.record_script:
var label = 'Awaiting Clarification';
var max = 5;

var table = 'x_153465_discovert_route_task_instance';
var filter = 'u_clarification_requested=true^parentISEMPTY^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe^ORprimary_office.tasking_authoritiesDYNAMIC90d1921e5f510100a9ad2572f2b477fe^NQu_clarification_requested=true^parentISNOTEMPTY^u_task_requesterDYNAMIC90d1921e5f510100a9ad2572f2b477fe^ORprimary_assignee.tasking_authoritiesDYNAMIC90d1921e5f510100a9ad2572f2b477fe';

var t = data; 
t.items = [];
t.record_watchers = [];
t.record_watchers.push({
  						'table':table,
                        'filter': filter
                       });

var a = new GlideAggregate(table);
a.addEncodedQuery(filter);
a.addAggregate("COUNT");
a.query();

var totcount = 0;

if(a.next()){
	totcount = a.getAggregate("COUNT");
}

var z = new GlideRecord(table);
z.addEncodedQuery(filter);
z.orderByDesc('sys_updated_on');
z.setLimit(max);
z.query();

while (z.next()) {
   t.items.push({
    			title: z.getValue('task_name') ,
    			type: 'link',
    			href: '?sys_id='+ z.getValue('sys_id') + '&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance'
  				}); 

  if(!z.canRead()){
    continue;
  }

  var a = {};
  if(z.short_description.nil()){
   	a.short_description = "(No description)";
  }
  a.__table = z.getTableName();
  a.type = 'record';  
}

t.items.sort(function(a, b) {
  return b.sortOrder - a.sortOrder;
});

t.items = t.items.slice(0, 5); 
t.count = totcount;

var link = {
  	title: gs.getMessage('View all requests'), 
  	type: 'link', 
  	href: '?id=discovertasker_detailsdrilldown&view=sp&table='+table+'&filter='+ filter + '&label='+label, 
  	items: []
};
t.items.push(link);
